import requests

def execute_script(script_code):
    url = "http://localhost:9200/_search"
    headers = {
        "Content-Type": "application/json"
    }
    payload = {
        "size": 0,
        "aggs": {
            "dynamic_agg": {
                "scripted_metric": {
                    "init_script": "state.transactions = []",
                    "map_script": script_code,
                    "combine_script": "double sum = 0; for (t in state.transactions) { sum += t } return sum;",
                    "reduce_script": "double totalSum = 0; for (sum in states) { totalSum += sum } return totalSum;"
                }
            }
        }
    }

    response = requests.post(url, headers=headers, json=payload)
    return response.json()

# Example usage
script_code = """
if (doc['value'].empty) {
    state.transactions.add(0);
} else {
    state.transactions.add(doc['value'].value);
}
"""
result = execute_script(script_code)
print(result)